bool sevendofDynamics::hasValidRuntimeParms
(
	const EcRealVector& parms
) const
{
	return parms.empty() || parms.size() == kNumJoints * kRuntimeParamsPerJoint;
}

bool sevendofDynamics::hasValidPayloadCom
(
	const EcRealVector& com
) const
{
	return com.size() == 3;
}

bool sevendofDynamics::shouldUseRuntimeParms
(
	const EcRealVector& parms
) const
{
	if (!parms.empty() && m_useExternalRuntimeParms)
	{
		return true;
	}
	return m_useInternalPayloadRuntimeParms && m_hasInternalPayloadOverride;
}

void sevendofDynamics::rebuildInternalPayloadRuntimeParms
(
)
{
	m_internalPayloadParms = m_defaultParms;
	m_hasInternalPayloadOverride = false;
	if (m_payloadMass <= 0.0 || !hasValidPayloadCom(m_payloadCom))
	{
		return;
	}
	const EcSizeT lastJointOffset = (kNumJoints - 1) * kRuntimeParamsPerJoint;
	const EcReal x = m_payloadCom[0];
	const EcReal y = m_payloadCom[1];
	const EcReal z = m_payloadCom[2];
	m_internalPayloadParms[lastJointOffset + 0] += m_payloadMass * (y * y + z * z);
	m_internalPayloadParms[lastJointOffset + 1] += -m_payloadMass * x * y;
	m_internalPayloadParms[lastJointOffset + 2] += -m_payloadMass * x * z;
	m_internalPayloadParms[lastJointOffset + 3] += m_payloadMass * (x * x + z * z);
	m_internalPayloadParms[lastJointOffset + 4] += -m_payloadMass * y * z;
	m_internalPayloadParms[lastJointOffset + 5] += m_payloadMass * (x * x + y * y);
	m_internalPayloadParms[lastJointOffset + 6] += m_payloadMass * x;
	m_internalPayloadParms[lastJointOffset + 7] += m_payloadMass * y;
	m_internalPayloadParms[lastJointOffset + 8] += m_payloadMass * z;
	m_internalPayloadParms[lastJointOffset + 9] += m_payloadMass;
	m_hasInternalPayloadOverride = true;
}

const EcRealVector& sevendofDynamics::activeRuntimeParms
(
	const EcRealVector& parms
) const
{
	if (!parms.empty() && m_useExternalRuntimeParms)
	{
		return parms;
	}
	if (m_useInternalPayloadRuntimeParms && m_hasInternalPayloadOverride)
	{
		return m_internalPayloadParms;
	}
	return m_defaultParms;
}

void sevendofDynamics::computeTorqueFromRegressor
(
	const double* regressor,
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcBoolean includeMotorInertia,
	EcBoolean includeFriction,
	EcRealVector& tau
) const
{
	(void)q;
	const EcRealVector& activeParms = activeRuntimeParms(parms);
	double thetaRigid[kNumJoints * kRigidParamsPerJoint];
	for (EcSizeT jointIdx = 0; jointIdx < kNumJoints; ++jointIdx)
	{
		const EcSizeT runtimeOffset = jointIdx * kRuntimeParamsPerJoint;
		const EcSizeT rigidOffset = jointIdx * kRigidParamsPerJoint;
		thetaRigid[rigidOffset + 0] = activeParms[runtimeOffset + 9];
		thetaRigid[rigidOffset + 1] = activeParms[runtimeOffset + 6];
		thetaRigid[rigidOffset + 2] = activeParms[runtimeOffset + 7];
		thetaRigid[rigidOffset + 3] = activeParms[runtimeOffset + 8];
		thetaRigid[rigidOffset + 4] = activeParms[runtimeOffset + 0];
		thetaRigid[rigidOffset + 5] = activeParms[runtimeOffset + 1];
		thetaRigid[rigidOffset + 6] = activeParms[runtimeOffset + 2];
		thetaRigid[rigidOffset + 7] = activeParms[runtimeOffset + 3];
		thetaRigid[rigidOffset + 8] = activeParms[runtimeOffset + 4];
		thetaRigid[rigidOffset + 9] = activeParms[runtimeOffset + 5];
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT rowIdx = 0; rowIdx < kNumJoints; ++rowIdx)
	{
		double value = 0.0;
		for (EcSizeT colIdx = 0; colIdx < kNumJoints * kRigidParamsPerJoint; ++colIdx)
		{
			value += regressor[rowIdx * kNumJoints * kRigidParamsPerJoint + colIdx] * thetaRigid[colIdx];
		}
		if (includeMotorInertia)
		{
			value += activeParms[rowIdx * kRuntimeParamsPerJoint + 10] * ddq[rowIdx];
		}
		if (includeFriction)
		{
			value += activeParms[rowIdx * kRuntimeParamsPerJoint + 11] * dq[rowIdx];
			value += activeParms[rowIdx * kRuntimeParamsPerJoint + 12] * signWithZero(dq[rowIdx]);
		}
		tau[rowIdx] = value;
	}
}

void sevendofDynamics::calculateGravityJointTorques
(
	const EcRealVector& q,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (q.size() != m_NumJoints)
	{
		return;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	const double gravity[3] = {m_gx, m_gy, m_gz};
	double regressor[kNumJoints * kNumJoints * kRigidParamsPerJoint];
	calculateIdentifiedGravityRegressorRowMajorCore(q.data(), gravity, regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, m_zeros, parms, false, false, tau);
}

void sevendofDynamics::computeRigidTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	computeRigidTorque(q, dq, ddq, EcRealVector(), tau);
}

void sevendofDynamics::computeRigidTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	EcRealVector tauM(m_NumJoints, 0.0);
	EcRealVector tauC(m_NumJoints, 0.0);
	EcRealVector tauG(m_NumJoints, 0.0);
	computeMassTorque(q, ddq, parms, tauM);
	computeCoriolisTorque(q, dq, parms, tauC);
	const double gravity[3] = {m_gx, m_gy, m_gz};
	double regressor[kNumJoints * kNumJoints * kRigidParamsPerJoint];
	calculateIdentifiedGravityRegressorRowMajorCore(q.data(), gravity, regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, m_zeros, parms, false, false, tauG);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		tau[idx] = tauM[idx] + tauC[idx] + tauG[idx];
	}
}

void sevendofDynamics::computeMassTorque
(
	const EcRealVector& q,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	computeMassTorque(q, ddq, EcRealVector(), tau);
}

void sevendofDynamics::computeMassTorque
(
	const EcRealVector& q,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	double regressor[kNumJoints * kNumJoints * kRigidParamsPerJoint];
	calculateIdentifiedZeroGravityRigidRegressorRowMajorCore(q.data(), m_zeros.data(), ddq.data(), regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, ddq, parms, false, false, tau);
}

void sevendofDynamics::computeCoriolisTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	EcRealVector& tau
) const
{
	computeCoriolisTorque(q, dq, EcRealVector(), tau);
}

void sevendofDynamics::computeCoriolisTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& parms,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints)
	{
		return;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	double regressor[kNumJoints * kNumJoints * kRigidParamsPerJoint];
	calculateIdentifiedZeroGravityRigidRegressorRowMajorCore(q.data(), dq.data(), m_zeros.data(), regressor);
	computeTorqueFromRegressor(regressor, q, dq, m_zeros, parms, false, false, tau);
}

void sevendofDynamics::computeGravityAxisTorques
(
	const EcRealVector& q,
	EcRealVector& tauGxUnit,
	EcRealVector& tauGyUnit,
	EcRealVector& tauGzUnit
) const
{
	computeGravityAxisTorques(q, EcRealVector(), tauGxUnit, tauGyUnit, tauGzUnit);
}

void sevendofDynamics::computeGravityAxisTorques
(
	const EcRealVector& q,
	const EcRealVector& parms,
	EcRealVector& tauGxUnit,
	EcRealVector& tauGyUnit,
	EcRealVector& tauGzUnit
) const
{
	if (q.size() != m_NumJoints)
	{
		return;
	}
	if (tauGxUnit.size() != m_NumJoints)
	{
		tauGxUnit.assign(m_NumJoints, 0.0);
	}
	if (tauGyUnit.size() != m_NumJoints)
	{
		tauGyUnit.assign(m_NumJoints, 0.0);
	}
	if (tauGzUnit.size() != m_NumJoints)
	{
		tauGzUnit.assign(m_NumJoints, 0.0);
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	const EcReal gxUnit[3] = {1.0, 0.0, 0.0};
	const EcReal gyUnit[3] = {0.0, 1.0, 0.0};
	const EcReal gzUnit[3] = {0.0, 0.0, 1.0};
	double regressor[kNumJoints * kNumJoints * kRigidParamsPerJoint];
	calculateIdentifiedGravityRegressorRowMajorCore(q.data(), gxUnit, regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, m_zeros, parms, false, false, tauGxUnit);
	calculateIdentifiedGravityRegressorRowMajorCore(q.data(), gyUnit, regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, m_zeros, parms, false, false, tauGyUnit);
	calculateIdentifiedGravityRegressorRowMajorCore(q.data(), gzUnit, regressor);
	computeTorqueFromRegressor(regressor, q, m_zeros, m_zeros, parms, false, false, tauGzUnit);
}

void sevendofDynamics::computeFrictionTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	computeFrictionTorque(q, dq, ddq, EcRealVector(), tau);
}

void sevendofDynamics::computeFrictionTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	const EcRealVector& activeParms = activeRuntimeParms(parms);
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		const EcSizeT runtimeOffset = idx * kRuntimeParamsPerJoint;
		tau[idx] = activeParms[runtimeOffset + 10] * ddq[idx]
			+ activeParms[runtimeOffset + 11] * dq[idx]
			+ activeParms[runtimeOffset + 12] * signWithZero(dq[idx]);
	}
}

void sevendofDynamics::computeInverseDynamics
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	computeInverseDynamics(q, dq, ddq, EcRealVector(), tau);
}

void sevendofDynamics::computeInverseDynamics
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	EcRealVector tauRigid(m_NumJoints, 0.0);
	EcRealVector tauFriction(m_NumJoints, 0.0);
	computeRigidTorque(q, dq, ddq, parms, tauRigid);
	computeFrictionTorque(q, dq, ddq, parms, tauFriction);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		tau[idx] = tauRigid[idx] + tauFriction[idx];
	}
}

EcBoolean sevendofDynamics::calculateEstimateJointToqruesLegacyInternal
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return false;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return false;
	}
	EcRealVector tauM(m_NumJoints, 0.0);
	EcRealVector tauC(m_NumJoints, 0.0);
	EcRealVector tauG(m_NumJoints, 0.0);
	EcRealVector tauF(m_NumJoints, 0.0);
	computeMassTorque(q, ddq, parms, tauM);
	computeCoriolisTorque(q, dq, parms, tauC);
	calculateGravityJointTorques(q, parms, tauG);
	computeFrictionTorque(q, dq, ddq, parms, tauF);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		tau[idx] = tauM[idx] + tauC[idx] + tauG[idx] + tauF[idx];
	}
	return true;
}

EcBoolean sevendofDynamics::calculateEstimateJointToqrues
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (m_runtimeTorqueMode == ROBUST_NO_TIME)
	{
		return calculateEstimateJointToqruesRobustNoTimeInternal(q, dq, ddq, parms, tau);
	}
	if (m_runtimeTorqueMode == ROBUST_TIMED_RESERVED)
	{
		// Reserved for a future timestamp/dt-aware implementation without changing
		// the shared external virtual function signature.
		return calculateEstimateJointToqruesLegacyInternal(q, dq, ddq, parms, tau);
	}
	return calculateEstimateJointToqruesLegacyInternal(q, dq, ddq, parms, tau);
}

void sevendofDynamics::calculateMomentumEstimatedJointTorques
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (!parms.empty() && m_useExternalRuntimeParms && !hasValidRuntimeParms(parms))
	{
		return;
	}
	EcRealVector tauM(m_NumJoints, 0.0);
	EcRealVector tauC(m_NumJoints, 0.0);
	computeMassTorque(q, ddq, parms, tauM);
	computeCoriolisTorque(q, dq, parms, tauC);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		tau[idx] = tauM[idx] + tauC[idx];
	}
}


