void sevendofDynamics::clearLastRuntimeDiagnostics(const EcBoolean validationOk)
{
	m_lastDiagnostics.q_raw.assign(kNumJoints, 0.0);
	m_lastDiagnostics.dq_raw.assign(kNumJoints, 0.0);
	m_lastDiagnostics.ddq_raw.assign(kNumJoints, 0.0);
	m_lastDiagnostics.q_used.assign(kNumJoints, 0.0);
	m_lastDiagnostics.dq_used.assign(kNumJoints, 0.0);
	m_lastDiagnostics.ddq_used.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_M_raw.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_C_raw.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_G.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_F_viscous.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_F_coulomb.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_F_hold.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_F_total.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_M_used.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_C_used.assign(kNumJoints, 0.0);
	m_lastDiagnostics.tau_total.assign(kNumJoints, 0.0);
	m_lastDiagnostics.friction_sign.assign(kNumJoints, 0.0);
	m_lastDiagnostics.hold_indicator.assign(kNumJoints, 0.0);
	m_lastDiagnostics.motion_state.assign(kNumJoints, 0.0);
	m_lastDiagnostics.wM.assign(kNumJoints, 0.0);
	m_lastDiagnostics.wC.assign(kNumJoints, 0.0);
	m_lastDiagnostics.validation_status.assign(kNumJoints, validationOk ? 1.0 : 0.0);
}

