void sevendofDynamics::resetRuntimeRobustState
(
)
{
	m_qUsed.assign(kNumJoints, 0.0);
	m_dqUsed.assign(kNumJoints, 0.0);
	m_ddqUsed.assign(kNumJoints, 0.0);
	m_qPrev.assign(kNumJoints, 0.0);
	m_dqPrev.assign(kNumJoints, 0.0);
	m_ddqPrev.assign(kNumJoints, 0.0);
	m_tauM.assign(kNumJoints, 0.0);
	m_tauC.assign(kNumJoints, 0.0);
	m_tauG.assign(kNumJoints, 0.0);
	m_tauF.assign(kNumJoints, 0.0);
	m_tauTotal.assign(kNumJoints, 0.0);
	m_tauFViscous.assign(kNumJoints, 0.0);
	m_tauFCoulomb.assign(kNumJoints, 0.0);
	m_tauFHold.assign(kNumJoints, 0.0);
	m_frictionSign.assign(kNumJoints, 0.0);
	m_holdIndicator.assign(kNumJoints, 0.0);
	m_motionState.assign(kNumJoints, 0.0);
	m_validationStatus.assign(kNumJoints, 0.0);
	m_hasRobustStateInitialized = false;
	clearLastRuntimeDiagnostics(false);
}

