void sevendofDynamics::getLastTorqueComponents
(
	EcRealVector& tauM,
	EcRealVector& tauC,
	EcRealVector& tauG,
	EcRealVector& tauF,
	EcRealVector& tauTotal
) const
{
	tauM = m_lastDiagnostics.tau_M_used;
	tauC = m_lastDiagnostics.tau_C_used;
	tauG = m_lastDiagnostics.tau_G;
	tauF = m_lastDiagnostics.tau_F_total;
	tauTotal = m_lastDiagnostics.tau_total;
}

void sevendofDynamics::getLastRuntimeSignals
(
	EcRealVector& qUsed,
	EcRealVector& dqUsed,
	EcRealVector& ddqUsed,
	EcRealVector& frictionSign,
	EcRealVector& motionState
) const
{
	qUsed = m_lastDiagnostics.q_used;
	dqUsed = m_lastDiagnostics.dq_used;
	ddqUsed = m_lastDiagnostics.ddq_used;
	frictionSign = m_lastDiagnostics.friction_sign;
	motionState = m_lastDiagnostics.motion_state;
}

EcBoolean sevendofDynamics::validateRuntimeInputNoTime
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	else
	{
		for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
		{
			tau[idx] = 0.0;
		}
	}
	clearLastRuntimeDiagnostics(false);
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return false;
	}
	if (!hasValidRuntimeParms(parms))
	{
		return false;
	}
	if (m_runtimeNoTimeConfig.enableInputValidation && m_runtimeValidationConfig.enableFiniteCheck)
	{
		for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
		{
			if (!isfinite(q[idx]) || !isfinite(dq[idx]) || !isfinite(ddq[idx]))
			{
				return false;
			}
		}
	}
	if (m_runtimeNoTimeConfig.enableInputValidation && m_runtimeValidationConfig.enableRadianRangeCheck)
	{
		EcSizeT suspiciousCount = 0;
		for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
		{
			if (fabs(q[idx]) > m_runtimeValidationConfig.maxAbsQForRadianCheck)
			{
				++suspiciousCount;
			}
		}
		if (suspiciousCount >= 2)
		{
			return false;
		}
	}
	if (m_runtimeNoTimeConfig.enableInputValidation && m_runtimeValidationConfig.enableGravityNormCheck)
	{
		const EcReal norm = sqrt(m_gx * m_gx + m_gy * m_gy + m_gz * m_gz);
		if (fabs(norm - m_runtimeValidationConfig.gravityNormExpected) > m_runtimeValidationConfig.gravityNormTolerance)
		{
			return false;
		}
	}
	return true;
}

void sevendofDynamics::updateMotionStateNoTime()
{
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		const EcReal vOff = configValue(m_frictionStateConfig.vOff, idx, 0.01);
		const EcReal vOn = configValue(m_frictionStateConfig.vOn, idx, 0.03);
		const EcReal aOff = configValue(m_frictionStateConfig.aOff, idx, 0.2);
		const EcReal smoothVelocity = configValue(m_frictionStateConfig.smoothVelocity, idx, 0.02);
		const EcReal previousSign = idx < m_frictionSign.size() ? m_frictionSign[idx] : 0.0;
		const EcInt32 previousState = idx < m_motionState.size() ? static_cast<EcInt32>(m_motionState[idx]) : STATIC;
		EcInt32 state = TRANSITION;
		EcReal sign = previousSign;
		EcReal hold = 0.0;
		if (!(m_runtimeNoTimeConfig.enableFrictionStateMachine && m_frictionStateConfig.enabled))
		{
			if (fabs(m_dqUsed[idx]) < vOff && fabs(m_ddqUsed[idx]) < aOff)
			{
				state = STATIC;
			}
			else if (m_dqUsed[idx] > 0.0)
			{
				state = MOVING_POSITIVE;
			}
			else if (m_dqUsed[idx] < 0.0)
			{
				state = MOVING_NEGATIVE;
			}
		}
		else if (fabs(m_dqUsed[idx]) < vOff && fabs(m_ddqUsed[idx]) < aOff)
		{
			state = STATIC;
		}
		else if (m_dqUsed[idx] > vOn)
		{
			state = MOVING_POSITIVE;
		}
		else if (m_dqUsed[idx] < -vOn)
		{
			state = MOVING_NEGATIVE;
		}
		else if (m_frictionStateConfig.enableHysteresis)
		{
			if (previousState == MOVING_POSITIVE && m_dqUsed[idx] > -vOff)
			{
				state = MOVING_POSITIVE;
			}
			else if (previousState == MOVING_NEGATIVE && m_dqUsed[idx] < vOff)
			{
				state = MOVING_NEGATIVE;
			}
		}
		if (state == STATIC)
		{
			sign = 0.0;
			hold = (m_runtimeNoTimeConfig.enableHoldMode && m_frictionStateConfig.enableHoldMode) ? 1.0 : 0.0;
		}
		else if (state == MOVING_POSITIVE)
		{
			sign = 1.0;
		}
		else if (state == MOVING_NEGATIVE)
		{
			sign = -1.0;
		}
		else if (m_frictionStateConfig.enableSmoothSign && smoothVelocity > 0.0)
		{
			sign = tanh(m_dqUsed[idx] / smoothVelocity);
		}
		m_motionState[idx] = static_cast<EcReal>(state);
		m_frictionSign[idx] = sign;
		m_holdIndicator[idx] = hold;
	}
}

void sevendofDynamics::computeFrictionTorqueRobustNoTimeInternal
(
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		const EcSizeT offset = idx * kRuntimeParamsPerJoint;
		const EcReal fv = parms[offset + 11];
		const EcReal fc = parms[offset + 12];
		const EcReal holdBias = configValue(m_frictionStateConfig.holdBias, idx, 0.0);
		m_tauFViscous[idx] = fv * m_dqUsed[idx];
		m_tauFCoulomb[idx] = fc * m_frictionSign[idx];
		m_tauFHold[idx] = holdBias * m_holdIndicator[idx];
		tau[idx] = m_tauFViscous[idx] + m_tauFCoulomb[idx] + m_tauFHold[idx];
	}
}

EcBoolean sevendofDynamics::calculateEstimateJointToqruesRobustNoTimeInternal
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	if (!validateRuntimeInputNoTime(q, dq, ddq, parms, tau))
	{
		return false;
	}
	const EcRealVector& activeParms = activeRuntimeParms(parms);
	clearLastRuntimeDiagnostics(true);
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		m_lastDiagnostics.q_raw[idx] = q[idx];
		m_lastDiagnostics.dq_raw[idx] = dq[idx];
		m_lastDiagnostics.ddq_raw[idx] = ddq[idx];
	}
	if (!m_hasRobustStateInitialized)
	{
		m_qUsed = q;
		m_dqUsed = dq;
		m_ddqUsed = ddq;
	}
	else
	{
		for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
		{
			const EcReal qAlpha = configValue(m_sampleSmoothingConfig.qAlpha, idx, 1.0);
			const EcReal dqAlpha = configValue(m_sampleSmoothingConfig.dqAlpha, idx, 1.0);
			const EcReal ddqAlpha = configValue(m_sampleSmoothingConfig.ddqAlpha, idx, 1.0);
			m_qUsed[idx] = (m_runtimeNoTimeConfig.enableSampleSmoothing && m_sampleSmoothingConfig.enabled)
				? qAlpha * q[idx] + (1.0 - qAlpha) * m_qPrev[idx] : q[idx];
			m_dqUsed[idx] = (m_runtimeNoTimeConfig.enableSampleSmoothing && m_sampleSmoothingConfig.enabled)
				? dqAlpha * dq[idx] + (1.0 - dqAlpha) * m_dqPrev[idx] : dq[idx];
			m_ddqUsed[idx] = (m_runtimeNoTimeConfig.enableSampleSmoothing && m_sampleSmoothingConfig.enabled)
				? ddqAlpha * ddq[idx] + (1.0 - ddqAlpha) * m_ddqPrev[idx] : ddq[idx];
		}
	}
	if (m_runtimeNoTimeConfig.enableDdqClamp && m_ddqClampConfig.enabled)
	{
		for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
		{
			const EcReal limit = fabs(configValue(m_ddqClampConfig.ddqLimit, idx, 50.0));
			if (m_ddqUsed[idx] > limit)
			{
				m_ddqUsed[idx] = limit;
			}
			else if (m_ddqUsed[idx] < -limit)
			{
				m_ddqUsed[idx] = -limit;
			}
		}
	}
	updateMotionStateNoTime();
	computeMassTorque(m_qUsed, m_ddqUsed, activeParms, m_tauM);
	computeCoriolisTorque(m_qUsed, m_dqUsed, activeParms, m_tauC);
	calculateGravityJointTorques(m_qUsed, activeParms, m_tauG);
	computeFrictionTorqueRobustNoTimeInternal(activeParms, m_tauF);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		EcReal wM = 1.0;
		EcReal wC = 1.0;
		if (m_runtimeNoTimeConfig.enableMCGate && m_mcGateConfig.enabled)
		{
			const EcInt32 state = static_cast<EcInt32>(m_motionState[idx]);
			if (state == STATIC)
			{
				wM = m_mcGateConfig.staticWM;
				wC = m_mcGateConfig.staticWC;
			}
			else if (state == TRANSITION)
			{
				wM = m_mcGateConfig.transitionWM;
				wC = m_mcGateConfig.transitionWC;
			}
			else
			{
				wM = m_mcGateConfig.dynamicWM;
				wC = m_mcGateConfig.dynamicWC;
			}
		}
		const EcReal tauMUsed = wM * m_tauM[idx];
		const EcReal tauCUsed = wC * m_tauC[idx];
		m_tauTotal[idx] = tauMUsed + tauCUsed + m_tauG[idx] + m_tauF[idx];
		tau[idx] = m_tauTotal[idx];
		m_lastDiagnostics.q_used[idx] = m_qUsed[idx];
		m_lastDiagnostics.dq_used[idx] = m_dqUsed[idx];
		m_lastDiagnostics.ddq_used[idx] = m_ddqUsed[idx];
		m_lastDiagnostics.tau_M_raw[idx] = m_tauM[idx];
		m_lastDiagnostics.tau_C_raw[idx] = m_tauC[idx];
		m_lastDiagnostics.tau_G[idx] = m_tauG[idx];
		m_lastDiagnostics.tau_F_viscous[idx] = m_tauFViscous[idx];
		m_lastDiagnostics.tau_F_coulomb[idx] = m_tauFCoulomb[idx];
		m_lastDiagnostics.tau_F_hold[idx] = m_tauFHold[idx];
		m_lastDiagnostics.tau_F_total[idx] = m_tauF[idx];
		m_lastDiagnostics.tau_M_used[idx] = tauMUsed;
		m_lastDiagnostics.tau_C_used[idx] = tauCUsed;
		m_lastDiagnostics.tau_total[idx] = m_tauTotal[idx];
		m_lastDiagnostics.friction_sign[idx] = m_frictionSign[idx];
		m_lastDiagnostics.hold_indicator[idx] = m_holdIndicator[idx];
		m_lastDiagnostics.motion_state[idx] = m_motionState[idx];
		m_lastDiagnostics.wM[idx] = wM;
		m_lastDiagnostics.wC[idx] = wC;
		m_lastDiagnostics.validation_status[idx] = 1.0;
	}
	m_qPrev = m_qUsed;
	m_dqPrev = m_dqUsed;
	m_ddqPrev = m_ddqUsed;
	m_hasRobustStateInitialized = true;
	return true;
}
